716	    /// Removes a previously added operation.
717	    ///
718	    /// This is useful when an operation is selected because the channel got disconnected and we
719	    /// want to try again to select a different operation instead.
720	    ///
721	    /// If new operations are added after removing some, the indices of removed operations will not
722	    /// be reused.
723	    ///
724	    /// # Panics
725	    ///
726	    /// An attempt to remove a non-existing or already removed operation will panic.
727	    ///
728	    /// # Examples
729	    ///
730	    /// ```
731	    /// use crossbeam_channel::{unbounded, Select};
732	    ///
733	    /// let (s1, r1) = unbounded::<i32>();
734	    /// let (_, r2) = unbounded::<i32>();
735	    ///
736	    /// let mut sel = Select::new();
737	    /// let oper1 = sel.recv(&r1);
738	    /// let oper2 = sel.recv(&r2);
739	    ///
740	    /// // Both operations are initially ready, so a random one will be executed.
741	    /// let oper = sel.select();
742	    /// assert_eq!(oper.index(), oper2);
743	    /// assert!(oper.recv(&r2).is_err());
744	    /// sel.remove(oper2);
745	    ///
746	    /// s1.send(10).unwrap();
747	    ///
748	    /// let oper = sel.select();
749	    /// assert_eq!(oper.index(), oper1);
750	    /// assert_eq!(oper.recv(&r1), Ok(10));
751	    /// ```
752	    pub fn remove(&mut self, index: usize) {
753	        assert!(
754	            index < self.next_index,
755	            "index out of bounds; {} >= {}",
756	            index,
757	            self.next_index,
758	        );
759	
760	        let i = self
761	            .handles
762	            .iter()
763	            .enumerate()
764	            .find(|(_, (_, i, _))| *i == index)
765	            .expect("no operation with this index")
766	            .0;
767	
768	        self.handles.swap_remove(i);
769	    }
