1034	    /// use std::thread;
1035	    /// use std::time::Duration;
1036	    /// use crossbeam_channel::{unbounded, Select};
1037	    ///
1038	    /// let (s1, r1) = unbounded();
1039	    /// let (s2, r2) = unbounded();
1040	    ///
1041	    /// # let t1 =
1042	    /// thread::spawn(move || {
1043	    ///     thread::sleep(Duration::from_secs(1));
1044	    ///     s1.send(10).unwrap();
1045	    /// });
1046	    /// # let t2 =
1047	    /// thread::spawn(move || s2.send(20).unwrap());
1048	    ///
1049	    /// let mut sel = Select::new();
1050	    /// let oper1 = sel.recv(&r1);
1051	    /// let oper2 = sel.recv(&r2);
