1054	    /// match sel.ready() {
1055	    ///     i if i == oper1 => assert_eq!(r1.try_recv(), Ok(10)),
1056	    ///     i if i == oper2 => assert_eq!(r2.try_recv(), Ok(20)),
1057	    ///     _ => unreachable!(),
